DBG001: PROC OPTIONS(MAIN);
   DCL WS-MSG CHAR(60);
   DCL 1 DFHCOMMAREA,
         2 INPUT-DATA CHAR(100);

   IF EIBCALEN = 0 THEN DO;
      WS-MSG = 'ERROR: COMMAREA IS EMPTY';
      EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
      RETURN;
   END;

   WS-MSG = 'INPUT RECEIVED SUCCESSFULLY';
   EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
END DBG001;

DBG002: PROC OPTIONS(MAIN);
   DCL IN-AMOUNT CHAR(10);
   DCL WS-AMOUNT FIXED DEC(7,2);
   DCL WS-MSG CHAR(60);

   IN-AMOUNT = '00125.50';

   IF VERIFY(IN-AMOUNT, ' 0123456789.') = 0 THEN DO;
      WS-AMOUNT = DECIMAL(IN-AMOUNT, 7, 2);
      WS-MSG = 'AMOUNT ACCEPTED';
   END;
   ELSE DO;
      WS-MSG = 'INVALID NUMERIC INPUT';
   END;

   PUT SKIP LIST(WS-MSG);
END DBG002;

DBG003: PROC OPTIONS(MAIN);
   DCL WS-RESP FIXED BIN(31);
   DCL WS-RESP2 FIXED BIN(31);
   DCL WS-MSG CHAR(80);
   DCL CUSTOMER-REC CHAR(100);
   DCL CUSTOMER-KEY CHAR(10) INIT('CUST000123');

   EXEC CICS READ FILE('CUSTFILE')
        INTO(CUSTOMER-REC)
        RIDFLD(CUSTOMER-KEY)
        RESP(WS-RESP)
        RESP2(WS-RESP2);

   IF WS-RESP ^= DFHRESP(NORMAL) THEN DO;
      IF WS-RESP = DFHRESP(NOTFND) THEN
         WS-MSG = 'CUSTOMER RECORD NOT FOUND';
      ELSE
         WS-MSG = 'READ FAILED - CHECK RESP AND RESP2';

      EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
      RETURN;
   END;

   WS-MSG = 'CUSTOMER RECORD READ SUCCESSFULLY';
   EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
END DBG003;
